function clean(v) { return String(v ?? '').trim(); }
let fileId = null, fileName = null;
try {
  const d = $('Google Drive Trigger').first()?.json;
  if (d && d.id) { fileId = d.id; fileName = d.name || d.id; }
} catch(e) {}
if (!fileId) {
  try {
    const q = $('Webhook').first()?.json?.query;
    fileId = clean(q?.file_id || '');
    fileName = clean(q?.file_name || fileId);
  } catch(e) {}
}
if (!fileId) throw new Error('Keine Datei-ID. Google Drive Trigger oder Webhook mit ?file_id= erforderlich.');
return [{ json: { fileId, fileName: fileName || fileId } }];

function clean(v) { return String(v ?? '').trim(); }
const { fileId, fileName } = $('Code - Datei-ID ermitteln').first().json;
const allHinweise = $('Google Sheets - Hinweise lesen').all().map(i => i.json);
const alreadyProcessed = allHinweise.some(h =>
  clean(h.type) === 'PICKLISTE_VERARBEITET' &&
  clean(h.message).startsWith('DATEI:' + fileName)
);
return [{ json: { skip: alreadyProcessed, fileId, fileName, reason: alreadyProcessed ? 'Bereits verarbeitet: ' + fileName : 'OK' } }];

const item = $input.first();
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
if (!buffer) throw new Error('Keine Binaerdaten im Feld data gefunden.');
const file = item.binary.data;
return [{ json: { file_base64: buffer.toString('base64'), mime_type: file.mimeType || 'application/pdf' } }];

const text = ($input.first().json?.content?.[0]?.text || '').trim();
const cleaned = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
let items;
try { items = JSON.parse(cleaned); }
catch(e) { throw new Error('Claude hat kein gueltiges JSON zurueckgegeben: ' + text.slice(0, 200)); }
if (!Array.isArray(items)) throw new Error('Keine Array-Antwort von Claude: ' + cleaned.slice(0, 100));
return [{ json: { items } }];

function clean(v) { return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').replace(/�|`|'|'/g, "'").trim(); }
function isActive(v) { return ['TRUE','1','JA','YES','AKTIV','ACTIVE'].includes(clean(v).toUpperCase()); }
function num(v) { const n = Number(String(v ?? '').replace(',', '.')); return Number.isFinite(n) ? n : null; }

const picklist      = $('Code - Claude Response parsen').first().json.items;
const fileName      = $('Code - Datei-ID ermitteln').first().json.fileName;
const allProdukte   = $('Google Sheets - Produkte lesen').all().map(i => i.json);
const allLager      = $('Google Sheets - Lagerchargen lesen').all().map(i => i.json);
const allHinweise   = $('Google Sheets - Hinweise lesen').all().map(i => i.json);

const now = new Date().toISOString();
let tsOffset = 0;
function nextTs() { return new Date(new Date(now).getTime() + tsOffset++).toISOString(); }

// c.status statt c.active (Lagerchargen haben 'status', nicht 'active')
const remainingByKey = {};
for (const c of allLager) {
  if (!isActive(c.status)) continue;
  const qty = num(c.remaining_qty);
  if (!qty || qty <= 0) continue;
  const pk = clean(c.product_key);
  remainingByKey[pk] = (remainingByKey[pk] || 0) + qty;
}

const slotUpdates  = [];
const toResolve    = [];
const auditEntries = [];
const warnings     = [];
const resolvableTypes = ['EMPTY_BATCH', 'LOW_STOCK', 'INSUFFICIENT_BATCH_STOCK', 'LOW_BATCH'];

for (const item of picklist) {
  const nayaxName = clean(item.name || '');
  const pickQty   = num(item.pick);
  if (!nayaxName || !pickQty || pickQty <= 0) continue;

  const slots = allProdukte.filter(p => clean(p.nayax_product_name) === nayaxName && isActive(p.active));
  if (!slots.length) { warnings.push('Nicht gefunden: "' + nayaxName + '"'); continue; }

  const pk             = clean(slots[0].product_key);
  const totalRemaining = remainingByKey[pk] || 0;

  // Verf�gbar = Backstock (remaining minus was bereits im Automaten)
  const currentInMachine = slots.reduce((sum, s) => sum + (num(s.current_machine_qty) || 0), 0);
  const availableFill    = Math.max(0, totalRemaining - currentInMachine);
  let effective          = Math.min(pickQty, availableFill);
  const wasCapped        = effective < pickQty;

  const updatedSlots = [];
  for (const slot of slots) {
    if (effective <= 0) break;
    const slotCurrent  = num(slot.current_machine_qty) || 0;
    const capacity     = num(slot.machine_capacity) || 999;
    const slotRoom     = Math.max(0, capacity - slotCurrent);
    const fillThisSlot = Math.min(slotRoom, effective);
    if (fillThisSlot <= 0) continue;
    effective -= fillThisSlot;
    const newQty = slotCurrent + fillThisSlot;
    slotUpdates.push({
      product_slot_id: clean(slot.product_slot_id),
      current_machine_qty: newQty,
      last_stock_update_source: 'WF9_PICKLISTE',
      last_stock_update_at: now
    });
    updatedSlots.push(clean(slot.product_slot_id) + '=' + newQty);
  }

  for (const h of allHinweise) {
    if (['TRUE','JA','YES','1'].includes(clean(h.resolved).toUpperCase())) continue;
    if (clean(h.product_key) === pk && resolvableTypes.includes(clean(h.type))) {
      toResolve.push({ created_at: clean(h.created_at), resolved: 'TRUE' });
    }
  }

  auditEntries.push({
    created_at: nextTs(),
    type: 'PICKLISTE_REFILL',
    severity: 'info',
    machine_id: '457107528',
    product_key: pk,
    nayax_product_name: nayaxName,
    message: nayaxName + ' pick=' + pickQty +
      (wasCapped ? ' (gecappt auf ' + Math.min(pickQty, availableFill) + ', backstock=' + availableFill + ')' : '') +
      '. Slots: ' + (updatedSlots.length ? updatedSlots.join(', ') : 'keine (0 verf�gbar)'),
    resolved: 'TRUE'
  });
}

if (warnings.length) {
  auditEntries.push({
    created_at: nextTs(), type: 'PICKLISTE_WARNING', severity: 'warning',
    machine_id: '457107528', product_key: '', nayax_product_name: '',
    message: 'Nicht zugeordnet: ' + warnings.join('; '), resolved: 'FALSE'
  });
}

auditEntries.push({
  created_at: nextTs(), type: 'PICKLISTE_VERARBEITET', severity: 'info',
  machine_id: '457107528', product_key: '', nayax_product_name: '',
  message: 'DATEI:' + fileName + ' - Produkte: ' + (picklist.length - warnings.length) + ', Slots: ' + slotUpdates.length,
  resolved: 'TRUE'
});

return [{ json: { ok: true, fileName, slotUpdates, toResolve, auditEntries, warnings,
  summary: { products_processed: picklist.length - warnings.length, slots_updated: slotUpdates.length,
             hints_resolved: toResolve.length, warnings: warnings.length } } }];

const result = $("Code - Pickliste verarbeiten").first().json;
const products = $("Google Sheets - Produkte lesen").all().map((item) => item.json);
const batches = $("Google Sheets - Lagerchargen lesen").all().map((item) => item.json);
const fileName = clean(result.fileName || $("Code - Datei-ID ermitteln").first().json.fileName);
const batchRunId = "wf9_" + new Date().toISOString().slice(0, 10);

function clean(value) {
  return String(value ?? "").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
}

function num(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

function isActive(value) {
  return ["TRUE", "1", "JA", "YES", "AKTIV", "ACTIVE", ""].includes(clean(value).toUpperCase());
}

function sanitize(value) {
  return clean(value).toUpperCase().replace(/[^A-Z0-9]+/g, "_").replace(/^_+|_+$/g, "");
}

function batchFor(productKey) {
  return batches
    .filter((batch) => clean(batch.product_key) === productKey)
    .filter((batch) => isActive(batch.status))
    .filter((batch) => (num(batch.remaining_qty) ?? 0) > 0)
    .sort((a, b) => clean(a.mhd).localeCompare(clean(b.mhd)) || clean(a.batch_id).localeCompare(clean(b.batch_id)))[0];
}

return (result.slotUpdates || []).flatMap((update) => {
  const slot = products.find((product) => clean(product.product_slot_id) === clean(update.product_slot_id));
  if (!slot) return [];
  const delta = (num(update.current_machine_qty) ?? 0) - (num(slot.current_machine_qty) ?? 0);
  if (delta <= 0) return [];
  const batch = batchFor(clean(slot.product_key));
  if (!batch) return [];
  const movementKey = ["MOV", "PICK", fileName, update.product_slot_id, batch.batch_id, delta].map(sanitize).join("_");
  return [{
    json: {
      event_type: "stock_movement",
      batch_run_id: batchRunId,
      data: {
        movement_key: movementKey,
        batch_key: clean(batch.batch_id),
        product_slot_key: clean(update.product_slot_id),
        movement_type: "pick",
        quantity_delta_total: -delta,
        quantity_delta_slot: delta,
        reason: "Pickliste verarbeitet: " + fileName,
        source: "wf9_pickliste",
        occurred_at: clean(update.last_stock_update_at) || new Date().toISOString(),
      },
    },
  }];
});

